        int len = temp.length;
        int[] table = new int[len + 1];

        table[0] = table[1] = 0; // 边界

        for (int n = 1; n < len; ++n) {
            int jump = table[n];

            while (temp[n] != temp[jump]) {
                // jump 向前追溯
                jump = table[jump];

                if (jump == 0) { // 为0，表示已回退到指定点
                    break;
                }
            }

            // 递推
            table[n + 1] = temp[n] == temp[jump] ? jump + 1 : 0;
        }

        return table;
    }
}
```

