public void foreach (NodeConsumer nodeConsumer){
        if (size == 0) return;

        Node node = head;

        int cursor = 0; // 遍历游标

        if (null != nodeConsumer) {
            if (!nodeConsumer.onNode(node, cursor)) {
                return;
            }
        }

        while (node.next != null) {
            cursor++;

            node = node.next; // 下一个节点

            if (null != nodeConsumer) {
                if (!nodeConsumer.onNode(node, cursor)) {
                    return;
                }
            }
        }
    }
