public SingleLinkedList insert (int i, Object val){
        checkBounds(i);

        if (i == size - 1) { // 尾部插入==尾部追加
            return add(val);
        }

        Node nodeI = new Node(val);

        foreach((node, id) -> {
            if (id == i - 1) { // 找到要插入的位置
                Node curNodeI = node.next; // 当前的i节点

                node.next = nodeI; // 指向新的i节点
                nodeI.next = curNodeI; // 新旧i节点关联
                size++;

                return false;
            }

            return true;
        });

        return this;
    }
}

